const data = $input.first().json;
const q = data.question || '';
const mode = data.mode;
const sa = data.student_answer || '';
const ctx = data.rag_context || '';

let msg;
if (mode === 'explain') {
  msg = 'Topic: ' + q + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON structure (no markdown, no extra text). The quiz array must contain EXACTLY 3 objects:
{"explanation":"3-5 sentences describing the topic","example":"one concrete practical example","quiz":[{"question":"first question","answer":"first answer"},{"question":"second question","answer":"second answer"},{"question":"third question","answer":"third answer"}],"recommendation":"what to study next"}';
} else if (mode === 'quiz') {
  msg = 'Topic: ' + q + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON structure (no markdown, no extra text). The quiz array must contain EXACTLY 3 objects:
{"quiz":[{"question":"first question","answer":"first answer"},{"question":"second question","answer":"second answer"},{"question":"third question","answer":"third answer"}]}';
} else {
  msg = 'Original question: ' + q + '
Student answer: ' + sa + '

Knowledge Base Context:
' + ctx + '

Respond ONLY with this exact JSON structure (no markdown, no extra text):
{"correct":true,"partial_credit":false,"score":85,"feedback":"detailed feedback for the student","correct_answer":"the ideal answer"}';
}

return [{ json: { ...data, user_message: msg } }];

const orig = $node['Input'].json;
let llm_output;
try {
  const raw = ($input.first().json.output || '').trim();
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
  llm_output = JSON.parse(cleaned);
} catch (e) {
  llm_output = { error: 'Failed to parse LLM response', raw: $input.first().json.output };
}
return [{ json: { ...orig, llm_output } }];
